{
  "sections":[
      {
         "name":"A",
         "description":"Multiple Choice, True/False, and Fill-in-the-Blank Questions",
         "questions":[
            {
               "questionNumber":1,
               "text":"Which of the following blood cells contain haemoglobin?",
               "type":"multiple-choice",
               "options":[
                  {
                     "letter":"a",
                     "text":"Lymphocytes",
                     "isCorrect":false
                  },
                  {
                     "letter":"b",
                     "text":"Phagocytes",
                     "isCorrect":false
                  },
                  {
                     "letter":"c",
                     "text":"Red blood cells",
                     "isCorrect":true
                  },
                  {
                     "letter":"d",
                     "text":"Platelets",
                     "isCorrect":false
                  }
               ],
               "correctAnswer":"c",
               "points":1
            },
            {
               "questionNumber":2,
               "text":"What is the function of the cornified layer of the epidermis of human skin?",
               "type":"multiple-choice",
               "options":[
                  {
                     "letter":"a",
                     "text":"Temperature regulation through sweating",
                     "isCorrect":true
                  },
                  {
                     "letter":"b",
                     "text":"Perception of sensation of temperature, pain and pressure",
                     "isCorrect":false
                  },
                  {
                     "letter":"c",
                     "text":"Synthesis of Vitamin D",
                     "isCorrect":false
                  },
                  {
                     "letter":"d",
                     "text":"Prevention of uncontrolled water loss by evaporation",
                     "isCorrect":false
                  }
               ],
               "correctAnswer":"a",
               "points":1
            },
            {
               "questionNumber":3,
               "text":"Which acid is produced in human muscle when there is not enough oxygen?",
               "type":"multiple-choice",
               "options":[
                  {
                     "letter":"a",
                     "text":"Lactic acid",
                     "isCorrect":true
                  },
                  {
                     "letter":"b",
                     "text":"Hydrochloric acid",
                     "isCorrect":false
                  },
                  {
                     "letter":"c",
                     "text":"Citric acid",
                     "isCorrect":false
                  },
                  {
                     "letter":"d",
                     "text":"Ascorbic acid",
                     "isCorrect":false
                  }
               ],
               "correctAnswer":"a",
               "points":1
            },
            {
               "questionNumber":4,
               "text":"Which of these statements below is not biologically correct?",
               "type":"multiple-choice",
               "options":[
                  {
                     "letter":"a",
                     "text":"All mammals are vertebrates",
                     "isCorrect":false
                  },
                  {
                     "letter":"b",
                     "text":"Frog's body is moist or rough skin",
                     "isCorrect":false
                  },
                  {
                     "letter":"c",
                     "text":"Birds have feathers",
                     "isCorrect":false
                  },
                  {
                     "letter":"d",
                     "text":"Amphibians have scales",
                     "isCorrect":true
                  }
               ],
               "correctAnswer":"d",
               "points":1
            },
            {
               "questionNumber":5,
               "text":"Which of these is not a function of joints?",
               "type":"multiple-choice",
               "options":[
                  {
                     "letter":"a",
                     "text":"Articulations",
                     "isCorrect":false
                  },
                  {
                     "letter":"b",
                     "text":"Allows bone growth",
                     "isCorrect":false
                  },
                  {
                     "letter":"c",
                     "text":"Enables mobility",
                     "isCorrect":false
                  },
                  {
                     "letter":"d",
                     "text":"Supports body",
                     "isCorrect":true
                  }
               ],
               "correctAnswer":"d",
               "points":1
            },
            {
               "questionNumber":6,
               "text":"Complete the following table with the corresponding type of contraceptive method: hormonal or non-hormonal or barrier.",
               "type":"fill-in-blank",
               "correctAnswer":"Spermicide: Barrier, Condom: Barrier, Implant: Hormonal, IUD: Non-Hormonal, Pills: Hormonal",
               "points":5
            },
            {
               "questionNumber":7,
               "text":"State whether each of the following statements is true or false.",
               "type":"true-false",
               "options":[
                  {
                     "letter":"a",
                     "text":"Mutations cannot be caused by copying errors in the genetic material during cell division.",
                     "isCorrect":false
                  },
                  {
                     "letter":"b",
                     "text":"Mutations can be caused by environmental changes.",
                     "isCorrect":true
                  },
                  {
                     "letter":"c",
                     "text":"Mutations can lead to death",
                     "isCorrect":true
                  },
                  {
                     "letter":"d",
                     "text":"Albinos are results of mutation in humans",
                     "isCorrect":true
                  },
                  {
                     "letter":"e",
                     "text":"Genotypic variations are visible",
                     "isCorrect":false
                  },
                  {
                     "letter":"f",
                     "text":"Phenotypic variations are visible",
                     "isCorrect":true
                  }
               ],
               "correctAnswer":"a) False, b) True, c) True, d) True, e) False, f) True",
               "points":6
            },
            {
               "questionNumber":8,
               "text":"Fill the blank spaces in the paragraph below choosing word from the following list: meiosis, fertilization, parent cells, haploid, diploid, gametes.",
               "type":"fill-in-blank",
               "correctAnswer":"The process of meiosis produces unique reproductive cells called gametes which have half the number of chromosomes as the parent cell. During fertilization the fusion of gametes from two individuals, restores the diploid condition. Gametes are haploid (containing only one set of chromosomes) while the zygote is diploid (containing two sets of chromosomes). Thus, sexually reproducing organisms alternate between haploid and diploid stages. In sexual reproduction, two individuals produce diploid offsprings that have characteristics from both parents. The gametes are produced from parent cells via the process called meiosis.",
               "points":7
            },
            {
               "questionNumber":9,
               "text":"Match the following blood cells with their functions:",
               "type":"matching",
               "options":[
                  {
                     "letter":"a",
                     "text":"White blood cells",
                     "match":"Defend the body against pathogens"
                  },
                  {
                     "letter":"b",
                     "text":"Red blood cells",
                     "match":"Transport of respiratory gases"
                  },
                  {
                     "letter":"c",
                     "text":"Platelets",
                     "match":"Clotting of blood"
                  }
               ],
               "correctAnswer":"a) White blood cells: Defend the body against pathogens, b) Red blood cells: Transport of respiratory gases, c) Platelets: Clotting of blood",
               "points":3
            },
            {
               "questionNumber":10,
               "text":"Write Yes if the statement is correct and No if it is wrong.",
               "type":"true-false",
               "options":[
                  {
                     "letter":"a",
                     "text":"ATP is released in the mitochondrion.",
                     "isCorrect":true
                  },
                  {
                     "letter":"b",
                     "text":"Aerobic respiration releases more energy than anaerobic respiration.",
                     "isCorrect":true
                  },
                  {
                     "letter":"c",
                     "text":"Cellular respiration occurs only in animal cells.",
                     "isCorrect":false
                  }
               ],
               "correctAnswer":"a) Yes, b) Yes, c) No",
               "points":3
            },
            {
               "questionNumber":11,
               "text":"Identify the parts of human reproductive system in which each of the following gametes is produced.",
               "type":"short-answer",
               "correctAnswer":"a) Sperm cell: Testis / testicle / male gonads, b) Ovum: Ovary / Ovaries / female gonads",
               "points":2
            },
            {
               "questionNumber":12,
               "text":"The age of four individuals is as follows: Individual A: 75-year-old grandfather, B: 35-year-old father, C: 28-year-old pregnant mother, D: 3-year-old boy",
               "type":"short-answer",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"Between the boy and the grandfather, who needs more milk?",
                     "type":"short-answer",
                     "correctAnswer":"The 3-year-old boy needs more milk.",
                     "points":1
                  },
                  {
                     "label":"b)",
                     "text":"Give reasons for your answer in (a).",
                     "type":"short-answer",
                     "correctAnswer":"Milk contains important proteins which are very essential for the growth/Body building /development and repair of the body. Children have growing bodies than adults.",
                     "points":2
                  },
                  {
                     "label":"c)",
                     "text":"Explain why a 28 year old pregnant mother needs more iron than a man of the same age.",
                     "type":"short-answer",
                     "correctAnswer":"A 28 year old mother needs extra iron because of the formation of more blood in both foetus and mother, formation of haemoglobin, formation of red blood cells, and to avoid anaemia.",
                     "points":2
                  }
               ],
               "points":5
            },
            {
               "questionNumber":13,
               "text":"Athletes are normally given glucose and not sucrose. Give a reason for this.",
               "type":"short-answer",
               "correctAnswer":"Glucose is a simple sugar/monosaccharide which can be broken down easily to produce energy.",
               "points":3
            },
            {
               "questionNumber":14,
               "text":"What is the basic measure can you take to protect yourself from contracting a disease?",
               "type":"short-answer",
               "correctAnswer":"Protection/ keeping proper hygiene, washing your hands often with soap and clean water, using sanitizer, cleaning and disinfecting surfaces that are often touched.",
               "points":2
            },
            {
               "questionNumber":15,
               "text":"Explain why farmers who grow cereals such as wheat, barley and rice must ensure that plants grow close to each other.",
               "type":"short-answer",
               "correctAnswer":"To allow cross pollination to take place easily, to ensure high yield production, to ensure support each other against wind, to allow maximum absorption of water/ Easy irrigation, to maximize land use.",
               "points":2
            },
            {
               "questionNumber":16,
               "text":"In your opinion, how would you deal with sexual assault?",
               "type":"short-answer",
               "correctAnswer":"Report to authorities, parents, teachers and guardians, help the victim to avoid to be isolated, giving the victim medical assistance, counseling, avoiding peer pressure, considering legal actions.",
               "points":2
            },
            {
               "questionNumber":17,
               "text":"Why should industrial plants treat their waste water before dumping in water bodies?",
               "type":"short-answer",
               "correctAnswer":"To prevent pollution, to prevent eutrophication, to avoid acidification of water bodies, to prevent water-borne diseases, to produce biogas, to avoid death of aquatic organisms, for being reused.",
               "points":4
            },
            {
               "questionNumber":18,
               "text":"Fill in the blank spaces.",
               "type":"fill-in-blank",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"Antigens bind at the ....... site forming ........... complexes",
                     "type":"fill-in-blank",
                     "correctAnswer":"Antigens bind at the active /antibody/ antigen-binding/binding site forming antigen-antibody complexes",
                     "points":1
                  },
                  {
                     "label":"b)",
                     "text":"Wee immunity is a naturally acquired immunity.",
                     "type":"fill-in-blank",
                     "correctAnswer":"Passive / active / adaptive immunity is a naturally acquired immunity.",
                     "points":1
                  }
               ],
               "points":3
            }
         ]
      },
      {
         "name":"B",
         "description":"Short Answer Questions",
         "questions":[
            {
               "questionNumber":19,
               "text":"How can we help someone with cholera? List any four practices to ensure good health.",
               "type":"short-answer",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"How can we help someone with cholera?",
                     "type":"short-answer",
                     "correctAnswer":"Take the patient immediately to the hospital for treatment, give the person rehydration salts/ fluids, give the patient the Intravenous fluids and electrolyte.",
                     "points":2
                  },
                  {
                     "label":"b)",
                     "text":"List any four practices to ensure good health.",
                     "type":"short-answer",
                     "correctAnswer":"Daily practices to ensure good health include: i) Brushing our teeth three times in a day and every after a meal, ii) Practicing moderate physical exercises, iii) Healthy eating: balanced diet, avoid too much fats/eating at close intervals, iv) Vaccination and immunisation practices",
                     "points":8
                  }
               ],
               "points":10
            },
            {
               "questionNumber":20,
               "text":"Describe the negative impact of monoculture system to the biological diversity in an ecosystem.",
               "type":"short-answer",
               "correctAnswer":"Monoculture crops have no genetic variability because they are not allowed to reproduce naturally. This exposes their pests and weeds to environmental adaptations and become resistant to chemicals used to control them as the only way to control pests in this set up is to use more chemical control mechanisms. Susceptibility to pests: The pests and weeds that attack them adapt easily to the environment and develop resistance to chemicals used to control them. Environment pollution through the use of dangerous synthetic chemicals/ Eutrophication, may cause eutrophication that affect aquatic life, use of fuel energy in combination with the chemical fertilizers and pesticides, cause environment pollution (Air, soil and water) and lead to climate change.",
               "points":10
            },
            {
               "questionNumber":21,
               "text":"Answer the following in relation to blood.",
               "type":"short-answer",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"What is blood plasma?",
                     "type":"short-answer",
                     "correctAnswer":"Blood plasma is the liquid part of blood.",
                     "points":1
                  },
                  {
                     "label":"b)",
                     "text":"Give the role of blood plasma.",
                     "type":"short-answer",
                     "correctAnswer":"Plasma transports blood cells, nutrients such as glucose and amino acids; transports antibodies, metabolic waste products... Transportation/ distribution of blood cells, Transportation /distribution of antibodies, Transportation / distribution of waste substances such as carbon dioxide and urea, Transportation / distribution of Hormones such as adrenaline, insulin and glucagon",
                     "points":2
                  },
                  {
                     "label":"c)",
                     "text":"The ABO blood group system has four blood groups. Name them.",
                     "type":"short-answer",
                     "correctAnswer":"A, B, AB, O",
                     "points":4
                  },
                  {
                     "label":"d)",
                     "text":"Blood groups can be positive (+) or negative (—) according to whether the blood contains or does not contain a particular factor. Name this factor.",
                     "type":"short-answer",
                     "correctAnswer":"Rhesus factor or Rh factor",
                     "points":1
                  },
                  {
                     "label":"e)",
                     "text":"Suggest a reason why it is important to know a person's blood group.",
                     "type":"short-answer",
                     "correctAnswer":"For proper blood transfusion, to avoid incompatibility of blood/agglutination/ in case of blood transfusion / For Safe organ transplant.",
                     "points":1
                  },
                  {
                     "label":"f)",
                     "text":"What is the function of platelets in the blood?",
                     "type":"short-answer",
                     "correctAnswer":"Platelets are responsible of blood clotting.",
                     "points":1
                  }
               ],
               "points":10
            },
            {
               "questionNumber":22,
               "text":"A man whose blood group is A marries a woman whose blood group B. If one of their children is blood group O:",
               "type":"short-answer",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"What are the genotypes of their parents?",
                     "type":"short-answer",
                     "correctAnswer":"AO and BO or I^I° and I^I°",
                     "points":2
                  },
                  {
                     "label":"b)",
                     "text":"Use a Punnett square to determine the genotype of the other children.",
                     "type":"short-answer",
                     "correctAnswer":"The genotypes of their children are: 25% or = AB, 25% or > BO, 25% or AO, 25% or + OO. Phenotype of parents: group A x group B, Genotype of parents: I* I° x I* I°, Gametes: I*, I° and I*, I°. The genotypes of their children are: 25% or KB, 25% or ~ I8 1°, 25% or IA 1°, 25% or + 1 1°",
                     "points":8
                  }
               ],
               "points":10
            },
            {
               "questionNumber":23,
               "text":"What do you understand by the term mitosis? Mitosis is essential in all living organisms. Give reasons to support your answer.",
               "type":"short-answer",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"What do you understand by the term mitosis?",
                     "type":"short-answer",
                     "correctAnswer":"Mitosis is a type of cell division in which a parent cell divides itself into two identical daughter cells which are genetically the same as the parent cell.",
                     "points":2
                  },
                  {
                     "label":"b)",
                     "text":"Mitosis is essential in all living organisms. Give reasons to support your answer.",
                     "type":"short-answer",
                     "correctAnswer":"It facilitates repair of worn out body tissues, it leads to body building hence growth, it brings about regeneration of parts of organisms, it is responsible of replacement of worn out cells, it provides a basis for asexual reproduction, it maintains genetic stability/the number of chromosomes in the nucleus is retained.",
                     "points":8
                  }
               ],
               "points":10
            }
         ]
      },
      {
         "name":"C",
         "description":"Essay/Long Answer Questions",
         "questions":[
            {
               "questionNumber":24,
               "text":"Assume you are performing an experiment to demonstrate osmosis.",
               "type":"essay",
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"Enumerate the apparatus and chemicals you may use in your demonstration.",
                     "type":"short-answer",
                     "correctAnswer":"Diagram of osmosis set-up: Two solutions and a membrane, Labels: e.g. water; salt or sugar solution; visking tubing or potato; beaker",
                     "points":5
                  },
                  {
                     "label":"b)",
                     "text":"Suggest a control that you might use in this activity.",
                     "type":"short-answer",
                     "correctAnswer":"Control: e.g. Only water in visking tubing and in the beaker; only water around the semi permeable membrane.",
                     "points":2
                  },
                  {
                     "label":"c)",
                     "text":"State the result(s) of the demonstration.",
                     "type":"short-answer",
                     "correctAnswer":"The visking tubing increase in size if it contains a salt or sugar solution. Or water moves from hypotonic solution to hypertonic",
                     "points":2
                  },
                  {
                     "label":"d)",
                     "text":"Briefly explain the result(s).",
                     "type":"short-answer",
                     "correctAnswer":"Osmosis is the movement of water molecules from a region of high concentration to a region of low concentration through a partially permeable membrane.",
                     "points":2
                  },
                  {
                     "label":"e)",
                     "text":"Suggest how storing food in salty water prevents the growth of bacteria or fungi on the stored food.",
                     "type":"short-answer",
                     "correctAnswer":"Storing food in salty water prevents the growth of bacteria or fungi on the stored food by creating an environment that is not suitable for their growth.",
                     "points":2
                  },
                  {
                     "label":"f)",
                     "text":"Apart from the method described in (e) above, suggest any other way of preventing food spoilage.",
                     "type":"short-answer",
                     "correctAnswer":"Other ways of preventing food spoilage include refrigeration, freezing, canning, and using preservatives.",
                     "points":1
                  }
               ],
               "points":15
            }
         ]
      }
   ]
}
